 // only when the text was actually shortened.
 function truncate(text, limit) {
   if (text.length <= limit) {
-    return text + "…";
+    return text;
   }
-  return text.slice(0, limit) + " …";
+
+  // The ellipsis is part of the maximum output length.
+  if (limit <= 0) {
+    return "";
+  }
+
+  let preview = text.slice(0, limit - 1);
+
+  // If the limit lands in the middle of a word, back up to its boundary.
+  if (!/\s$/.test(preview) && !/\s/.test(text[limit - 1])) {
+    const boundary = preview.search(/\s[^\s]*$/);
+    if (boundary !== -1) {
+      preview = preview.slice(0, boundary);
+    } else {
+      preview = "";
+    }
+  }
+
+  return preview.trimEnd() + "…";
 }

 module.exports = { truncate };
